#include<bits/stdc++.h>
using namespace std;
int n,c;
int a[1000001],b[1000001];
long long cost[1000001];
int main()
{
    scanf("%d%d",&n,&c);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&b[i]);
    }
    for(int i=1;i<=n;i++)
    {
    	if(b[i]>a[i])
    	{
    		cost[i]=b[i]-a[i];
		}
		else
		{
			cost[i]=0;
		}
    }
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        ans=ans+cost[i]*c;
    }
    printf("%lld",ans);
    return 0;
}
